import {mkdirSync} from 'node:fs';
import path from 'node:path';

function piPluginScript(): string {
	return `\
// pk extension — auto-generated by pk init
import {spawnSync} from 'node:child_process';
import {readFileSync} from 'node:fs';
import {fileURLToPath} from 'node:url';
import path from 'node:path';
import type {ExtensionAPI} from '@earendil-works/pi-coding-agent';

function getKnowledgeDir(): string {
  try {
    const root = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '..', '..');
    const cfg = JSON.parse(readFileSync(path.join(root, '.pk.json'), 'utf8')) as {knowledgeDir?: string};
    return cfg.knowledgeDir ?? '';
  } catch {
    return '';
  }
}

export default function (pi: ExtensionAPI) {
  pi.on('before_agent_start', async (event, _ctx) => {
    const dir = getKnowledgeDir();
    const proc = spawnSync('pk', ['prime'], {
      encoding: 'utf-8',
      ...(dir ? {env: {...process.env, PK_KNOWLEDGE_DIR: dir}} : {}),
    });
    const output = proc.stdout?.trim() ?? '';
    return output
      ? {systemPrompt: output + '\\n\\n' + event.systemPrompt}
      : undefined;
  });

  pi.on('tool_call', async (event, _ctx) => {
    if (event.toolName === 'bash' && event.input?.command) {
      const dir = getKnowledgeDir();
      if (dir) {
        event.input.command = \`export PK_KNOWLEDGE_DIR=\${dir}\\n\` + event.input.command;
      }
    }
  });
}
`;
}

export async function writePiPlugin(projectRoot: string): Promise<void> {
	const pluginPath = path.join(projectRoot, '.pi', 'extensions', 'pk-eval.ts');
	mkdirSync(path.dirname(pluginPath), {recursive: true});
	await Bun.write(pluginPath, piPluginScript());
}
